questions.solutionCode:
function solve(requirementsJson) {
  const reqs = JSON.parse(requirementsJson);

  // Формируем условие фильтрации: value.op == 'c' || value.op == 'u'
  const filterCondition = reqs.filterOps
    .map(op => "value.op == '" + op + "'")
    .join(' || ');

  // Формируем routing expression с null-safety
  const routeExpr = "value." + reqs.routeField + " != null ? '" +
    reqs.topicPrefix + "-' + value." + reqs.routeField +
    " : '" + reqs.topicPrefix + "-default'";

  return {
    'transforms': 'filter,unwrap,route',
    'transforms.filter.type': 'io.debezium.transforms.Filter',
    'transforms.filter.language': 'jsr223.groovy',
    'transforms.filter.condition': filterCondition,
    'transforms.unwrap.type': 'io.debezium.transforms.ExtractNewRecordState',
    'transforms.route.type': 'io.debezium.transforms.ContentBasedRouter',
    'transforms.route.language': 'jsr223.groovy',
    'transforms.route.topic.expression': routeExpr
  };
}
